head.script:
// 자회사 계정
// inswave1 / inswave1
// 물류 > 공통 > 자회사 거래처 등록
// 동원선박물류

// 247033 / 1111

// dt 요청으로 탭 숨김처리함
// [국제물류] 탭 숨김처리 요청(화면에서 보이지 않게만 처리해 주세요)

scwin.pos_clnt = 0;
scwin.gJudgeYn = "0";
scwin.memJson = $c.data.getMemInfo();
scwin.g_sLoginDept = scwin.memJson.acctDeptCd //"<%=loginDTO.getAcctDeptCd()%>"
scwin.vCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 소속 자회사
scwin.vCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd; // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.isNewCrn = "F"; //CRN 신규 생성 여부 (T :False , F: False); 

// hidden 컴포넌트...
scwin.txt_clntNoValChk;
scwin.txt_clntNo = 0;
scwin.txt_clntLupCond = 0;
scwin.txt_sysCls = 0;
scwin.txt_payIdx;
scwin.txt_createYn = "0";
scwin.txt_updateYn = 0;
scwin.txt_rowCount = -1;
scwin.txt_saveType = -1;
scwin.txt_payCondRowCount = 0;
scwin.txt_payAcntRowCount = 0;
scwin.updateRow; // 추가한 전역변수

scwin.onpageload = function () { };

// UDC에 값 세팅 방법
// UDC값 초기화(scwin.onpageload 이후 세팅됨) 
scwin.onUdcCompleted = function () {
    // console.log("----------- onUdcCompleted");
    const codeOptions = [
        { grpCd: "ZZ594", compID: "lc_clntTyp" },
        { grpCd: "FI018", compID: "clntBusiClsCd" },    //  "^선택,<%= GauceUtil.getCodeList("FI018") %>" // 사업자구분
        { grpCd: "ZZ018", compID: "accountClntKndCd" }, // "<%=GauceUtil.getCodeList("ZZ018")%>"
        { grpCd: "SD020", compID: "tb_Grid1:stmtPrdClsCd" }, // "<%=GauceUtil.getGridCombo("SD020", false)%>" 
        { grpCd: "SD010", compID: "tb_Grid1:collMoneyCntShtCd" }, // "<%=GauceUtil.getGridCombo("SD010", false)%>"
        { grpCd: "ZZ006", compID: "tb_Grid1:collMoneyCrcCd" }, // "<%=GauceUtil.getGridCombo("ZZ006", false)%>"
        { grpCd: "FM041", compID: "tb_Grid2:payCycCd" }, // "<%=GauceUtil.getGridCombo("FM041", false)%>"
        { grpCd: "ZZ522", compID: "tb_Grid2:payDd" }, // "<%=GauceUtil.getGridCombo("ZZ522",  false)%>" 
        { grpCd: "FM018", compID: "tb_Grid2:payCntShtCd", opt: { "range": "3, 99" } }, // "<%=GauceUtil.getGridCombo("FM018", 3, "99", false)%>" 
        { grpCd: "ZZ006", compID: "tb_Grid2:payCrcCd" }, // "<%=GauceUtil.getGridCombo("ZZ006", false)%>"
        { grpCd: "FM019", compID: "tb_Grid3:payClsCd" }, // "<%=GauceUtil.getGridCombo("FM019", false)%>"
        { grpCd: "FM063", compID: "tb_Grid3:elecStmtBankCd" }, // "<%=GauceUtil.getGridCombo("FM063",  false)%>" 
    ];
    $c.data.setCommonCode(codeOptions, scwin.f_load);
};

scwin.f_load = async function () {

    lc_clntTyp.addItem('전체', '', null, 0);

    lc_clntTyp.setSelectedIndex(0);

    scwin.f_ContentsDisable();
    scwin.txt_payIdx = "1";

    await scwin.f_retrieveJudge();

    scwin.gJudgeYn = "0";
    for (var i = 0; i < ds_judge.getTotalRow(); i++) {
        if (scwin.g_sLoginDept == ds_judge.getCellData(i, "col1")) {
            scwin.gJudgeYn = "1";
        }
    } 

    $c.gus.cfDisableBtn(
        [
            b_Update,
            b_Cancel,
            b_Save,
            b_Update2,
            b_Cancel2,
            b_Save2,
            bAddRow,
            bDeleteRow,
            bUndoRow,
            crn_regist,
            bAddRow1,
            bDeleteRow1,
            bUndoRow1,
            bAddRow2,
            bDeleteRow2,
            bUndoRow2
        ]
    );

    if (scwin.vCoCd == "023") {

        txt_clntTypNm.setValue("거래처타입");
        lc_clntTyp.show("");
        // mxTab.Format = '' +
        //     '<T> divid="mxTab_page1" title="수금조건"</T>' +
        //     '<T> divid="mxTab_page2" title="지급조건"</T>' +
        //     '<T> divid="mxTab_page3" title="지급계좌"</T>' +
        //     '<T> divid="mxTab_page4" title="국제물류"</T>';


        // document.getElementById('mxTab_page4').style.display = ''; // to-do
    } else {
        txt_clntTypNm.setValue("");
        lc_clntTyp.hide("");
        mxTab.hideTab(3);
        // mxTab.Format = '' +
        //     '<T> divid="mxTab_page1" title="수금조건"</T>' +
        //     '<T> divid="mxTab_page2" title="지급조건"</T>' +
        //     '<T> divid="mxTab_page3" title="지급계좌"</T>';

        // document.getElementById('mxTab_page4').style.display = 'none'; // to-do
    }

    if (scwin.vCoCd == "029") {
        tb_Grid2.setColumnVisible("payAcctDeptNm", false)
    }

    if (scwin.vCoCd == "017") {
        txt_opusNm.setValue("OPUS거래처코드");
        txt_opusClntNo.show("");
    } else {
        txt_opusNm.setValue("");
        txt_opusClntNo.hide("");
    }
};


/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {

    let submitObj = $p.getComponentById(e.id);

    switch (submitObj) {
        case sbm_accountCustomer:
            await scwin.sbm_accountCustomer_submitdone(e);
            break;

        case sbm_RetrieveAccountCustomerList:
            await scwin.sbm_RetrieveAccountCustomerList_submitdone(e);
            break;

        case sbm_saveAccountCustomer:
            await scwin.sbm_saveAccountCustomer_submitdone(e);
            break;


        default:
            break;
    }

};


/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {

    const e = await $c.sbm.execute(sbmObj);

    if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        if (e.responseJSON.resultDataSet[0].Code == -1) return;
        await scwin.submitdone(e);
    };

};


//-------------------------------------------------------------------------
// 회계 거래처 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    scwin.txt_saveType = "2";  // 0:신규, 1:수정, 2:조회
    scwin.txt_payIdx = "1";
    await mxTab.setSelectedTabIndex(0) // mxTab.ActiveIndex = 1

    scwin.f_ContentsDisable();

    var searchType = lux_clntLupCond.getValue();
    var searchText = qrySearch.getValue();
    var crn = "";
    scwin.busiNm = "";
    let clntNo = "";
    let clntNm = "";

    switch (searchType) {
        case "0": //거래처명
            clntNm = searchText;
            break;
        case "1": //거래처번호 
            clntNo = searchText;
            break;
        case "2": //사업자번호
            crn = searchText;
            break;
        case "3": //사업자명
            scwin.busiNm = searchText;
            break;
        default:
            return false;
    }

    if (searchText == "") {
        msgArr = new Array(2);
        msgArr[0] = "검색어";
        msgArr[1] = "글자(숫자) 한(두)";

        $c.gus.cfAlertMsg(MSG_CM_ERR_011, msgArr);
        qrySearch.focus();
        return false;
    }

    // var condition = "?clntLupCond=T"   //clntLupCond=S" 에서 T 로 바꿈. 검색콤보로 UI 변경되어 쿼리 분기처리함 . 2016.11.15   
    //     + "&coClsCd=" + scwin.vCoClsCd
    //     + "&coCd=" + scwin.vCoCd
    //     + "&crn=" + crn
    //     + "&busiNm=" + busiNm
    //     + "&clntNo=" + clntNo
    //     + "&clntNm=" + clntNm
    //     + "&clntDelYn=" + lux_useYn.BindColVal
    //     ;

    // ds_accountCustomer.DataID = "/cm.bc.clnt.clntmgnt.RetrieveAccountCustomerListCMD.do" + condition;

    dma_accountCustomer.set("clntLupCond", "T");
    dma_accountCustomer.set("coClsCd", scwin.vCoClsCd);
    dma_accountCustomer.set("coCd", scwin.vCoCd);
    dma_accountCustomer.set("crn", crn);
    dma_accountCustomer.set("busiNm", scwin.busiNm);
    dma_accountCustomer.set("clntNo", clntNo);
    dma_accountCustomer.set("clntNm", clntNm);
    dma_accountCustomer.set("clntDelYn", lux_useYn.getValue());

    await scwin.submitExcute(sbm_accountCustomer);

    $c.gus.cfDisableBtn(
        [
            b_Cancel,
            b_Save,
            b_Cancel2,
            b_Save2,
            bAddRow,
            bDeleteRow,
            bUndoRow,
            bAddRow1,
            bDeleteRow1,
            bUndoRow1,
            bAddRow2,
            bDeleteRow2,
            bUndoRow2
        ]
    );
    $c.gus.cfEnableBtnOnly([b_Create, b_Create2, b_Update, b_Update2]);
}

//-------------------------------------------------------------------------
// 수금, 지급조건, 지급계좌 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCollPayAcnt = async function () {
    sbm_RetrieveAccountCustomerList.action =
        "/cm.bc.clnt.clntmgnt.RetrieveCollMoneyPayCondAcntListCMD.do?clntNo=" + scwin.txt_clntNo

    await scwin.submitExcute(sbm_RetrieveAccountCustomerList);

    // const e = await $c.sbm.execute(sbm_RetrieveAccountCustomerList); // tr_RetrieveAccountCustomerList.Post();
    // if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
    //     await scwin.sbm_RetrieveAccountCustomerList_submitdone(e);
    // };

}




