    $c.gus.cfEnableObj(zip_search, true);  // 우편번호찾기 이미지 활성화
    $c.gus.cfEnableObj(bank_search, true);  // 은행팝업 이미지 활성화
    $c.gus.cfEnableObj(ed_coCd, true);  // 회사코드 
    // ed_coCd.setDisabled(true);
    $c.gus.cfEnableObj(img_company, true);  // 회사찾기 이미지 
    $c.gus.cfEnableObj(zip, true);	 // 우편번호
