    clntDeptNm.setDisabled(false);
    clntPersPstNm.setDisabled(false);
    clntPersNm.setDisabled(false);
    clntTelNo.setDisabled(false);
    clntMpNo.setDisabled(false);
    clntFaxNo.setDisabled(false);
    clntEmail.setDisabled(false);
}


