//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {

    scwin.f_ContentsEnable2();
    const insertIdx = ds_accountCustomer.insertRow();
    gr_accountCustomer.setFocusedCell(insertIdx, "clntNm", false);

    clntBusiClsCd.setSelectedIndex(0);
    accountClntKndCd.setSelectedIndex(2); // 거래처 종류 :일반
    clntDelYn.setSelectedIndex(0); // CodeValue

    scwin.txt_createYn = "1";
    scwin.txt_updateYn = "0";
    scwin.txt_saveType = "0";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소

    tb_Grid1.setReadOnly("grid", false);
    tb_Grid2.setReadOnly("grid", false);
    tb_Grid3.setReadOnly("grid", false);

    $c.gus.cfDisableBtn([b_Create, b_Update, b_Create2, b_Update2]);
    $c.gus.cfEnableBtnOnly([b_Cancel, b_Cancel2, b_Save, b_Save2]);
    ed_coCd.setValue(scwin.vCoCd);


    // 행추가, 행삭제, 취소가 disable 되어있는 상태로 탭이동후 수정버튼 클릭시 행추가, 행삭제, 취소 enable되지 않아
    // 추가하였음.
    let tabIdx = mxTab.getSelectedTabIndex()
    switch (tabIdx) {
        case 0:
            $c.gus.cfEnableBtnOnly(
                [


                    b_Cancel,
                    b_Cancel2,
                    b_Save,
                    b_Save2,

                    bAddRow, bUndoRow, bDeleteRow,

                    bAddRow1,
                    bDeleteRow1,
                    bUndoRow1,
                    bAddRow2,
                    bDeleteRow2,
                    bUndoRow2
                ]
            );
            break;
        case 1:
            $c.gus.cfEnableBtnOnly(
                [
                    b_Cancel,
                    b_Cancel2,
                    b_Save,
                    b_Save2,
                    bAddRow1,
                    bDeleteRow1,
                    bUndoRow1,
                    bAddRow2,
                    bDeleteRow2,
                    bUndoRow2
                ]
            );
            break;
        case 2:
            $c.gus.cfEnableBtnOnly(
                [
                    b_Cancel,
                    b_Cancel2,
                    b_Save,
                    b_Save2,
                    bAddRow1,
                    bDeleteRow1,
                    bUndoRow1,
                    bAddRow2,
                    bDeleteRow2,
                    bUndoRow2
                ]
            );
            break;

        default:
            break;
    }


    // 거래처명 input을 활성화함. asis에서 어디서 활성화하는지 알수가 없어 추가하였음
    clntNm.setDisabled(false);
    if (!$c.gus.cfIsNull(ed_coCd.getValue())) {
        scwin.f_PopUpCompanyInfo();
    }
    $c.gus.cfEnableObj(emp_search, false);  // 사원팝업 이미지 비활성화
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    // disable 처리

    b_Cancel2.setDisabled(false);
    scwin.f_ContentsEnable();
    scwin.txt_createYn = "0";
    scwin.txt_updateYn = "1";   // 수정인경우
    scwin.txt_saveType = "1";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
    $c.gus.cfDisableBtn([b_Create, b_Update, b_Create2, b_Update2, crn_search, crn_regist]);
    $c.gus.cfEnableBtnOnly([b_Cancel, b_Cancel2, b_Save, b_Save2]);
    $c.gus.cfDisableObjects(
        [
            txt_coNm,
            clntBusiClsCd,
            bizcondNm,
            biztypeNm,
            crn_search,
            crn,
            crn_regist
        ]
    ); // 사업자번호등록정보부분

    repstNm.setDisabled(true);
    clntNm.setDisabled(false);
    // 수정버튼 클릭시 주소 disable, 회사코드 enable (2026.03.30)
    busiAddr.setDisabled(true);

    // 수정전에 포커스된 행 수정시에 팝업 뜨게하기위해 추가함.
    scwin.updateRow = gr_accountCustomer.getFocusedRowIndex();

