scwin.f_Cancel = function () {
    // 취소 확인

    if (ds_accountCustomer.getRowPosition() > ds_accountCustomer.getTotalRow()
        || ds_accountCustomer.getModifiedIndex().length > 0) {
        // ds_accountCustomer.Undo(ds_accountCustomer.rowPosition);
        $c.data.undoRow(ds_accountCustomer, "Y");

        // tobe - 취소 버튼 클릭 시 동작이 달라 추가함
        $c.data.undoAll(ds_collMoneyCond);
        $c.data.undoAll(ds_payCond)
        $c.data.undoAll(ds_payAcnt)
    }

    scwin.f_ContentsDisable();
    var vAccountCustomerCount = ds_accountCustomer.getTotalRow();
    if (vAccountCustomerCount > 0) {
        $c.gus.cfDisableBtn(
            [
                b_Cancel,
                b_Save,
                b_Cancel2,
                b_Save2,
                bAddRow,
                bDeleteRow,
                bUndoRow,
                bAddRow1,
                bDeleteRow1,
                bUndoRow1,
                bAddRow2,
                bDeleteRow2,
                bUndoRow2
            ]
        );

    } else {
        $c.gus.cfDisableBtn(
            [
                b_Cancel,
                b_Update,
                b_Save,
                b_Cancel2,
                b_Update2,
                b_Save2,
                bAddRow,
                bDeleteRow,
                bUndoRow,
                bAddRow1,
                bDeleteRow1,
                bUndoRow1,
                bAddRow2,
                bDeleteRow2,
                bUndoRow2
            ]
        );
    }

    scwin.txt_saveType = "4";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
    scwin.txt_createYn = "0";
    scwin.txt_updateYn = "0";
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {

    // 매출입구분
    var vSellClntYn = sellClntYn.getValue(); 	// 매출
    var vPchsClntYn = pchsClntYn.getValue();  	// 매입

    // 결제구분은 Bill 수령후를 선택할 수 없게함
    if (ds_collMoneyCond.getCellData(ds_collMoneyCond.rowPosition, 'stmtPrdClsCd') == "02") {
        $c.win.alert("결제 구분은 Bill 수령후를 선택하실 수 없습니다.");
        return 0;
    }

    // 수정시에는 삭제여부가 1(True)인경우는 체크하지 않음.
    if (clntDelYn.getValue() == 0) {
        //if(!cfValidate([chkRegistInfo]) ||  !cfValidate([chkRegistInfo1])  ){ return false;	} 
    }

    // 신규로 등록시에는 수금조건을 필수입력해야된다.

    if (ds_accountCustomer.getCellData(ds_accountCustomer.rowPosition, "accountClntKndCd") != "EM") {

        // 매출입구분 항목 체크
        if (vSellClntYn == false && vPchsClntYn == false) {
            $c.win.alert("매출입구분은 필수입력 사항입니다.");
            return false;
        }
    }

    // 거래처번호, 사업자번호 체크 	
    let vCrn = crn.getValue().trimAll();

    //사업자등록번호 필수
    if (crn.getValue() == "") {
        $c.win.alert("사업자등록번호는 필수 입력입니다.");
        return;
    }

    if (scwin.vCoCd == "023") {//BIDC WMS시스템 거래처 타입
        if (lc_clntTyp.getValue() == "") {
            $c.win.alert("거래처타입을 선택해주세요.")
            return;
        }
    }

    if (scwin.vCoCd == "017") {//LA법인 OPUS거래처코드 중복체크
        if (txt_opusClntNo.value != "") {
            let chkClnt = scwin.chkOpusClntNo(clntNo.getValue(), txt_opusClntNo.getValue());
            if (!chkClnt) {
                return;
            }
        }
    }

    //변경한 데이터가 있는지 체크한다. 	
    if (ds_accountCustomer.getModifiedIndex().length == false
        && ds_collMoneyCond.getModifiedIndex().length == false
        && ds_payCond.getModifiedIndex().length == false
        && ds_payAcnt.getModifiedIndex().length == false) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    // 저장확인 
    let confirmVal = await $c.win.confirm("저장하시겠습니까?")
    if (confirmVal == true) {
        scwin.pos_clnt = ds_accountCustomer.getRowPosition();

        ds_accountCustomer.setCellData(scwin.pos_clnt, "coClsCd", scwin.vCoClsCd);

        for (var i = 0; i < ds_accountCustomer.getTotalRow(); i++) {
            if (ds_accountCustomer.getRowStatus(i) == "C") { // 1 -> 2
                ds_accountCustomer.setCellData(i, "clntKndCd", "SA");

                if (sellClntYn.getValue() && !pchsClntYn.getValue()) {
                    ds_accountCustomer.setCellData(i, "busiPchsSellCls", "1");
                }
                if (!sellClntYn.getValue() && pchsClntYn.getValue()) {
                    ds_accountCustomer.setCellData(i, "busiPchsSellCls", "2");
                }
                if (sellClntYn.getValue() && pchsClntYn.getValue()) {
                    ds_accountCustomer.setCellData(i, "busiPchsSellCls", "3");
                }
            }

            ds_accountCustomer.setCellData(i, "originalCrn", ds_accountCustomer.getCellData(i, "crn"));
        }

        scwin.txt_saveType = "3"; // 타입이 저장
        // $c.sbm.execute(sbm_saveAccountCustomer); // tr_saveAccountCustomer.Post();
        await scwin.submitExcute(sbm_saveAccountCustomer);

    }
}

//-------------------------------------------------------------------------
// 지급조건, 지급계좌 신규
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    if (scwin.txt_createYn == "0" && scwin.txt_updateYn == "0") {
        $c.win.alert("추가하시기전 신규등록모드나 수정모드로 전환하십시오.");
        return false;
    }

    let idx = scwin.txt_payIdx;
    let seqVal;
    switch (idx) {
        case "1":
            scwin.txt_payIdx = "1";
            // 지급조건과 지급계약에 거래처번호와 SEQ 할당
            let rowPos1 = ds_collMoneyCond.insertRow();
            ds_collMoneyCond.setCellData(rowPos1, "clntNo", clntNo.getValue());

            if (rowPos1 == 0) {
                ds_collMoneyCond.setCellData(rowPos1, "seq", 1);
            } else {
                seqVal = scwin.f_SetSEQ()
                ds_collMoneyCond.setCellData(rowPos1, "seq", seqVal);
            }
            ds_collMoneyCond.setCellData(rowPos1, "stmtPrdDd", 0);
            ds_collMoneyCond.setCellData(rowPos1, "draftDdCnt", 0);
            ds_collMoneyCond.setCellData(rowPos1, "collMoneyCrcCd", "KRW");
            tb_Grid1.setFocusedCell(rowPos1, "seq", false);
            break;
        case "2":
            // 지급조건과 지급계약에 거래처번호와 SEQ 할당
            let rowPos2 = ds_payCond.insertRow();
            ds_payCond.setCellData(rowPos2, "clntNo", clntNo.getValue());
            ds_payCond.setCellData(rowPos2, "cashRt", 100);

            if (rowPos2 == 0) {
                ds_payCond.setCellData(rowPos2, "seq", 1);
            } else {
                seqVal = scwin.f_SetSEQ()
                ds_payCond.setCellData(rowPos2, "seq", scwin.f_SetSEQ());
            }
            ds_payCond.setCellData(rowPos2, "confirmYn", 0);
            ds_payCond.setCellData(rowPos2, "payCrcCd", "KRW");
            tb_Grid2.setFocusedCell(rowPos2, "seq", false);
            console.log(rowPos2);
            break;
        case "3":
            let rowPos3 = ds_payAcnt.insertRow();
            ds_payAcnt.setCellData(rowPos3, "clntNo", clntNo.getValue());
            if (rowPos3 == 0) {
                ds_payAcnt.setCellData(rowPos3, "seq", 1);
            } else {
                seqVal = scwin.f_SetSEQ()
                ds_payAcnt.setCellData(rowPos3, "seq", scwin.f_SetSEQ());
            }
            ds_payAcnt.setCellData(rowPos3, "confirmYn", 0);
            tb_Grid3.setFocusedCell(rowPos3, "seq", false);
            break;

        default:
            break;
    }
    $c.gus.cfEnableKeyData();
}


//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_delMarked = function () {
    let rowPos;
    let rowPos2;
    let rowPos3;
    switch (scwin.txt_payIdx) {
        case "1":
            rowPos = ds_collMoneyCond.getRowPosition();
            if (ds_collMoneyCond.getCellData(rowPos, "confirmYn") == "1")
                $c.gus.cfAlertMsg("확인된 건은 삭제 할 수 없습니다.");
            else {
                let rowStatus = ds_collMoneyCond.getRowStatus(rowPos);

                if (rowPos == null) return;
                if (rowStatus != "C") return;

                if (ds_collMoneyCond.getTotalRow() > rowPos) {
                    ds_collMoneyCond.deleteRow(rowPos);
                    ds_collMoneyCond.removeRow(rowPos);
                    tb_Grid1.setFocusedCell(rowPos, "seq", false);
                } else {
                    ds_collMoneyCond.deleteRow(rowPos);
                    ds_collMoneyCond.removeRow(rowPos);
                }
            }
            break;
        case "2":
            rowPos2 = ds_payCond.getRowPosition();
            if (ds_payCond.getCellData(rowPos2, "confirmYn") == "1")
                $c.gus.cfAlertMsg("확인된 건은 삭제 할 수 없습니다.");
            else {
                let rowStatus2 = ds_payCond.getRowStatus(rowPos2);

                if (rowPos2 == null) return;
                if (rowStatus2 != "C") return;

                if (ds_payCond.getTotalRow() > rowPos2) {
                    ds_payCond.deleteRow(rowPos2);
                    ds_payCond.removeRow(rowPos2);
                    tb_Grid2.setFocusedCell(rowPos2, "seq", false);
                } else {
                    ds_payCond.deleteRow(rowPos2);
                    ds_payCond.removeRow(rowPos2);
                }
            }
            break;
        case "3":
            rowPos3 = ds_payAcnt.getRowPosition();
            if (ds_payAcnt.getCellData(rowPos3, "confirmYn") == "1")
                $c.gus.cfAlertMsg("확인된 건은 삭제 할 수 없습니다.");
            else {
                let rowStatus3 = ds_payAcnt.getRowStatus(rowPos3);

                if (rowPos3 == null) return;
                if (rowStatus3 != "C") return;

                if (ds_payAcnt.getTotalRow() > rowPos3) {
                    ds_payAcnt.deleteRow(rowPos3);
                    ds_payAcnt.removeRow(rowPos3);
                    tb_Grid3.setFocusedCell(rowPos3, "seq", false);
                } else {
                    ds_payAcnt.deleteRow(rowPos3);
                    ds_payAcnt.removeRow(rowPos3);
                }
            }
            break;
        default:
            break;
    }
}

