//-------------------------------------------------------------------------
// 바이트 크기 체크
//-------------------------------------------------------------------------
scwin.bytelength = function (bstr) {
    let len = bstr.length;
    for (ii = 0; ii < bstr.length; ii++) {
        xx = bstr.substr(ii, 1).charCodeAt(0);
        if (xx > 127) { len++; }
    }
    return len;
}

//-------------------------------------------------------------------------
// 그리드 높이 늘리기
//-------------------------------------------------------------------------
scwin.f_grdHeiht = function (size) {
    var vDsIdx = scwin.txt_payIdx;
    let objGrd;

    switch (vDsIdx) {
        case "1":
            objGrd = "tb_Grid1";
            break;
        case "2":
            objGrd = "tb_Grid2";
            break;
        case "3":
            objGrd = "tb_Grid3";
            break;
        default:
            break;
    }

    objGrd = $p.getComponentById(objGrd);
    var strHeight = objGrd.style.height;
    var intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;

    if (size < 0 && intHeight <= 30) return;

    if (intHeight > 0) {
        objGrd.style.height = intHeight + "px";
    }

    var strTop = btn_table.style.top;
    var strTop2 = parseInt(strTop.replace("px", ""));

    strTop2 = strTop2 + size;

    if (strTop2 > 0) {
        btn_table.style.top = strTop2 + "px";
    }

    parent.frames("clntIframe").height = document.body.scrollHeight;
    parent.resizeHeight("clntIframe");
};


//-------------------------------------------------------------------------
// 엑셀다운로드
//-------------------------------------------------------------------------
scwin.f_downExcelSheet = async function () {
    var vDsIdx = scwin.txt_payIdx;
    var vObjGrd;
    var sheetTitle;

    switch (vDsIdx) {
        case "1":
            if (ds_collMoneyCond.getTotalRow() < 1) {
                $c.win.alert("수금조건내역이 없습니다.");
                return false;
            }
            vObjGrd = "tb_Grid1";
            sheetTitle = "수금조건";
            break;
        case "2":
            if (ds_payCond.getTotalRow() < 1) {
                $c.win.alert("지급조건내역이 없습니다.");
                return false;
            }
            vObjGrd = "tb_Grid2";
            sheetTitle = "지급조건";
            break;
        case "3":
            if (ds_payAcnt.getTotalRow() < 1) {
                $c.win.alert("지급계좌내역이 없습니다.");
                return false;
            }
            vObjGrd = "tb_Grid3";
            sheetTitle = "지급계좌";
            break;
        default:
            break;
    }

    var objGrd = $p.getComponentById(vObjGrd);

    let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
        const grdObj = objGrd;
        const infoArr = [];
        const options = {
            fileName: sheetTitle + ".xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName: sheetTitle,
        };
        $c.data.downloadGridViewExcel(grdObj, options, infoArr);
    }
}

