    udc_dept.setSelectId('retrieveAcctDeptCdInfo6')
    rtnList = udc_dept.cfCommonPopUp(
        (rtnList) => {
            if (rtnList != null) {
                if (rtnList[0] == "N/A") return false;

                if (idx == "1") {
                    moneyPos = ds_collMoneyCond.getRowPosition();
                    ds_collMoneyCond.setCellData(moneyPos, "collMoneyAcctDeptCd", rtnList[0]);	//수금귀속부서코드
                    ds_collMoneyCond.setCellData(moneyPos, "collMoneyAcctDeptNm", rtnList[1]);	//수금귀속부서명
                } else if (idx == "2") {
                    payPos = ds_payCond.getRowPosition();
                    ds_payCond.setCellData(payPos, "payAcctDeptCd", rtnList[0]);	//지급귀속부서코드
                    ds_payCond.setCellData(payPos, "payAcctDeptNm", rtnList[1]);	//지급귀속부서명
                }
            } else {
                if (idx == "1") {
                    moneyPos = ds_collMoneyCond.getRowPosition();
                    ds_collMoneyCond.setCellData(moneyPos, "collMoneyAcctDeptCd", "")//수금귀속부서코드
                    ds_collMoneyCond.setCellData(moneyPos, "collMoneyAcctDeptNm", "")//수금귀속부서명
                } else if (idx == "2") {
                    payPos = ds_payCond.getRowPosition();
                    ds_payCond.setCellData(payPos, "payAcctDeptCd", "")//지급귀속부서코드
                    ds_payCond.setCellData(payPos, "payAcctDeptNm", "")//지급귀속부서명
                }
            }

        }, '', '', "T", null, null, null, "3,4,5,6,7,8,9,10", param,
        null, null, null, null, null, null, vTitle, null);
}

