scwin.f_openZipPopUp = async function (type) {
    var vZip = "";
    var vTitle = "우편번호, 우편번호, 주소";

    if (type == 1) vZip = zip.getValue();
    else if (type == 2) vZip = em_busiZip.getValue();

    var rtnList = new Array();
    // var popupResult = window.showModalDialog("/cm/zz/newzipcodePopup.jsp", "", 
    // "dialogHeight:400px;dialogWidth:530px;center:yes;scroll:no;status:no;help:no");

    let v_url = "/ui/cm/zz/newzipcodePopup.xml";
    let opts = {
        id: "pupup",
        popupName: "",
        modal: true,
        type: "browserPopup",
        width: 530,
        height: 400,
        title: ""
    };

    popupResult = await $c.win.openPopup(v_url, opts, rtnList);

    // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
    if (popupResult != null) {
        if (rtnList[0] == "N/A") return;

        if (type == 1) {
            zip.setValue(rtnList[0]);
            addr1.setValue(rtnList[1]);
            addr2.focus();
        } else if (type == 2) {
            em_busiZip.setValue(rtnList[0]);
            txt_busiAddr1.setValue(rtnList[2]);
            txt_busiAddr2.focus();
        }
        zip.setValue(popupResult.zip);
        addr1.setValue(popupResult.addr1);
        addr2.focus();

    } else {
        zip.setValue("");
        addr1.setValue("");
        addr2.setValue("");
    }
}

