scwin.f_crnOpenPopUp = function () {

    //법인사업자
    var vClntBusiClsCd = clntBusiClsCd.getValue();   // 사업자구분코드

    var rtnList = new Array();
    rtnList = cfCommonPopUp('retrieveCrnInfo', crn.value, '', "T",
        null, null, null, null, null, null, null, null, null, null, null, null, null); //  사업자등록번호

    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            sccwin.f_setCrnInfo();
            return false;
        }

        var vCrn = crn.getValue();
        var vClntNm = clntNm.getValue();
        var vZip = "";
        var vBusiAddr = "";
        var vTmpZip = zip.getValue();
        var vTmpAddr1 = addr1.getValue();
        var vTmpAddr2 = addr1.getValue();

        crn.setValue(rtnList[0]);	//사업자등록번호

        if (vClntNm.trimAll() == "") {
            clntNm.setValue(rtnList[1]);	//사업자명
        }
        if (txt_busiNm.getValue() == "") {
            txt_busiNm.setValue(rtnList[1]);	//법인사업자명
        }

        clntBusiClsCd.setValue(rtnList[2]);
        repstNm.setValue(rtnList[3]);
        bizcondNm.setValue(rtnList[4]);
        biztypeNm.setValue(rtnList[5]);

        if (vTmpZip.trim() == "" && vTmpAddr1.trim() == "" && vTmpAddr2.trim() == "") {
            zip.setValue(rtnList[6]);
            addr1.setValue(rtnList[7]);
            addr2.setValue(rtnList[8]);
        }

        if (rtnList[6] != "" && rtnList[6].length > 5) {
            vZip = "(" + rtnList[6].substr(0, 3) + "-" + rtnList[6].substr(3, 6) + ") ";
        }

        vBusiAddr = vZip + rtnList[7] + "  " + rtnList[8];
        busiAddr.setValue(vBusiAddr);

        // 사업자등록번호가 거래처로 등록여부에 대한 메시지
        var param = scwin.vCoCd;
        let rtnList2 = cfCommonPopUp('retrieveClntCrnInfo', crn.value, '', null, null, null, null, null, param, null, null, null, null, "T", null, null); //  거래처정보

        if (rtnList2 > 0) {
            $c.win.alert("사업자등록번호가 이미 다른 거래처에 등록되어 있습니다.");
        }
    }
}

