//-------------------------------------------------------------------------
// 지급조건 지급계좌 순번할당..
//-------------------------------------------------------------------------
scwin.f_SetSEQ = function () {
    var vTabIndex = scwin.txt_payIdx;
    var vTmpSeq = 0;
    var vTmpVal;
    var vObjGrd;
    var vPayCountRow = 0;

    switch (vTabIndex) {
        case "1":
            vObjGrd = "ds_collMoneyCond";
            break;
        case "2":
            vObjGrd = "ds_payCond";
            break;
        case "3":
            vObjGrd = "ds_payAcnt";
            break;
        default:
            break;
    }

    var objDataSet = $p.getComponentById(vObjGrd);
    var vPayCountRow = objDataSet.getTotalRow();

    if (vPayCountRow > 0) {
        for (i = 0; i < vPayCountRow; i++) {
            vTmpVal = objDataSet.getCellData(i, "seq");
            if (vTmpVal > vTmpSeq) {
                vTmpSeq = vTmpVal;
            }
        }
    }
    return Number(vTmpSeq) + 1;
}

//-------------------------------------------------------------------------
// 수금조건, 지급조건, 지급계좌 전체 데이터 비교
//-------------------------------------------------------------------------
scwin.f_CompareCollMoneyPayCondAcnt = function (pDataSet) {
    var vDataSet = $p.getComponentById(pDataSet);
    var vCountRow = vDataSet.getTotalRow();
    var vReturnCount = 0;
    var vSize = 0;

    if (pDataSet == "ds_collMoneyCond") vSize = 8;
    if (pDataSet == "ds_payCond") vSize = 9;
    if (pDataSet == "ds_payAcnt") vSize = 7;

    for (var h = 0; h < vCountRow; h++) {
        var tmpReturnVal = scwin.f_RowCompareCollMoneyPayCondAcnt(pDataSet, h, vSize);
        if (tmpReturnVal > 0) vReturnCount++;
    }

    return vReturnCount;
}


//-------------------------------------------------------------------------
// 수금조건, 지급조건, 지급계좌 한로우 데이터 비교
//-------------------------------------------------------------------------
scwin.f_RowCompareCollMoneyPayCondAcnt = function (pDataSet, pRow, pSize) {

    var vDataSet = $p.getComponentById(pDataSet);
    var vCountRow = vDataSet.getTotalRow();
    var vCol = new Array(pSize);
    var vTmpCol = new Array(pSize);

    let rowData;
    let rowData2;

    if (pDataSet == "ds_collMoneyCond") {
        // 수금조건
        rowData = ds_collMoneyCond.getRowJSON(pRow) || {};
        vCol[0] = rowData["adptDt"]
        vCol[1] = rowData["collMoneyAcctDeptCd"]
        vCol[2] = rowData["stmtPrdClsCd"]
        vCol[3] = rowData["stmtPrdDd"]
        vCol[4] = rowData["collMoneyCntShtCd"]
        vCol[5] = rowData["draftDdCnt"]
        vCol[6] = rowData["collMoneyCrcCd"]
        vCol[7] = rowData["collMoneyBankbookNo"]

    } else if (pDataSet == "ds_payCond") {
        // 지급조건
        rowData = ds_payCond.getRowJSON(pRow) || {};
        vCol[0] = rowData["adptDt"];
        vCol[1] = rowData["payAcctDeptCd"];
        vCol[2] = rowData["payCycCd"];
        vCol[3] = rowData["payDd"];
        vCol[4] = rowData["payCntShtCd"];
        vCol[5] = rowData["draftDdCntCd"];
        vCol[6] = rowData["payCrcCd"];
        vCol[7] = rowData["cashRt"];
        vCol[8] = rowData["draftRt"];
    } else {
        // 지급계좌
        rowData = ds_payAcnt.getRowJSON(pRow) || {};
        vCol[0] = rowData["adptDt"];
        vCol[1] = rowData["payClsCd"];
        vCol[2] = rowData["bankCd"];
        vCol[3] = rowData["bankAcntNo"];
        vCol[4] = rowData["dpstrNm"];
        vCol[5] = rowData["elecStmtBankCd"];
        vCol[6] = rowData["transfCmisDeductYn"];
    }

    var vDuplCount = 0;
    for (var i = 0; i < vCountRow; i++) {
        if (pRow == i) continue;

        if (pDataSet == "ds_collMoneyCond") {
            // 수금조건
            rowData2 = ds_collMoneyCond.getRowJSON(i) || {};
            vTmpCol[0] = rowData2["adptDt"];
            vTmpCol[1] = rowData2["collMoneyAcctDeptCd"];
            vTmpCol[2] = rowData2["stmtPrdClsCd"];
            vTmpCol[3] = rowData2["stmtPrdDd"];
            vTmpCol[4] = rowData2["collMoneyCntShtCd"];
            vTmpCol[5] = rowData2["draftDdCnt"];
            vTmpCol[6] = rowData2["collMoneyCrcCd"];
            vTmpCol[7] = rowData2["collMoneyBankbookNo"];
        } else if (pDataSet == "ds_payCond") {
            // 지급조건
            rowData2 = ds_payCond.getRowPosition(i) || {};
            vTmpCol[0] = rowData2["adptDt"];
            vTmpCol[1] = rowData2["payAcctDeptCd"];
            vTmpCol[2] = rowData2["payCycCd"];
            vTmpCol[3] = rowData2["payDd"];
            vTmpCol[4] = rowData2["payCntShtCd"];
            vTmpCol[5] = rowData2["draftDdCntCd"];
            vTmpCol[6] = rowData2["payCrcCd"];
            vTmpCol[7] = rowData2["cashRt"];
            vTmpCol[8] = rowData2["draftRt"];
        } else {
            // 지급계좌
            rowData2 = ds_payAcnt.getRowJSON(i) || {};
            vTmpCol[0] = rowData2["adptDt"];
            vTmpCol[1] = rowData2["payClsCd"];
            vTmpCol[2] = rowData2["bankCd"];
            vTmpCol[3] = rowData2["bankAcntNo"];
            vTmpCol[4] = rowData2["dpstrNm"];
            vTmpCol[5] = rowData2["elecStmtBankCd"];
            vTmpCol[6] = rowData2["transfCmisDeductYn"];
        }

        var vColEqual = 0;
        for (var j = 0; j < pSize; j++) {
            if (vCol[j] == vTmpCol[j]) {
                vColEqual++;
            }
        }
        if (vColEqual == pSize) vDuplCount++;
    }
    return vDuplCount;
}

//-------------------------------------------------------------------------
// 전화번호 유효성 체크
//-------------------------------------------------------------------------
scwin.f_CheckTelNumber = function (vIndex) {
    var vTelNo = "";
    var vAlertMsg = "";
    var vRtrurnId = "";

    switch (vIndex) {
        case "1":
            // 휴대폰번호
            vTelNo = clntMpNo.getValue();
            vAlertMsg = "휴대폰전화번호를 정확하게 입력해 주십시오.";
            vRtrurnId = "clntMpNo";
            break;
        case "2":
            // 유선전화
            vTelNo = clntTelNo.getValue();
            vAlertMsg = "유선전화번호를 정확하게 입력해 주십시오.";
            vRtrurnId = "clntTelNo";
            break;
        default:
            // FAX
            vTelNo = clntFaxNo.getValue();
            vAlertMsg = "FAX번호를 정확하게 입력해 주십시오.";
            vRtrurnId = "clntFaxNo";
            break;
    }

    if (vTelNo.trim() != "") {
        // var vValidTelNumber = covTelNumberValidator_validate(vTelNo);
        var vValidTelNumber = $c.str.isPhone(vTelNo);
        if (!vValidTelNumber) {
            $c.win.alert(vAlertMsg);
            vId = $p.getComponentById(vRtrurnId);
            vId.focus();
            return false;
        }
    }
}

