        ed_coCd.getValue(), txt_coNm.getValue(), "T", null
        , null, null, null, null, null
        , null, null, null, null, null
        , null, null
    );

    if (rtnList[0] != "N/A" && !$c.gus.cfIsNull(rtnList)) {
        ed_coCd.setValue(rtnList[0]);        // 코드
