// LA법인 OPUS거래처코드 중복체크
scwin.chkOpusClntNo = function (clntNo, opusClntNo) {

    // SELECT 절 
    var param1 =
        "CLNT_NO 		as COL1 "
        + ",CLNT_NM 	as COL2 "
        + ",'' 			as COL3 "
        + ",'' 			as COL4 "
        + ",'' 			as COL5 "
        + ",'' 			as COL6 "
        + ",'' 			as COL7 "
        + ",'' 			as COL8 "
        + ",'' 			as COL9 "
        + ",'' 			as COL10 "
        ;

    // 대상테이블
    var param2 = "TB_ZZ510";
    // 조회조건
    var param3 = "";

    if (clntNo != "") {
        param3 = "AND CO_CD= '017' AND CLNT_NO != '" + clntNo + "' AND OLD_CLNT_NO = '" + opusClntNo + "'";
    } else {
        param3 = "AND CO_CD= '017' AND OLD_CLNT_NO = '" + opusClntNo + "'";
    }

    // ORDER BY
    var param4 = "COL1";
    // ds_chkOpusClntNo.DataId =
    //     "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1
    //     + "&param2=" + param2
    //     + "&param3=" + param3
    //     + "&param4=" + param4;

    ds_chkOpusClntNo.set("sysCd", "CommonEBC")
    ds_chkOpusClntNo.set("queryId", "dinymicQueryTest")
    ds_chkOpusClntNo.set("param1", param1)
    ds_chkOpusClntNo.set("param2", param2)
    ds_chkOpusClntNo.set("param3", param3)
    ds_chkOpusClntNo.set("param4", param4)

    $c.sbm.execute(sbm_chkOpusClntNo); // ds_chkOpusClntNo.Reset();

    // to-do
    if (ds_chkOpusClntNo.CountRow > 0) {
        $c.win.alert("OPUS거래처코드가 이미 등록되어있습니다. 중복등록 불가합니다. "
            + "( 거래처코드: " + ds_chkOpusClntNo.get("col1") + " )");
        return false;
    } else {
        return true;
    }
}

