// 수금수단 Combo 선택
scwin.tb_Grid1_onafteredit = async function (rowIndex, columnIndex, value) {
    // for=tb_Grid1 event=OnExit(row,colid,olddata)
    let vTmpData = "30";
    let vstmtPrdClsCd = ds_collMoneyCond.getCellData(rowIndex, "stmtPrdClsCd");

    let colid = tb_Grid1.getColumnID(columnIndex);

    if (value != "") vTmpData = scwin.oldValue;

    if (colid == "stmtPrdDd") {
        var vstmtPrdDd = ds_collMoneyCond.getCellData(rowIndex, "stmtPrdDd");

        // 결제조건 구분선택시 결재기한은 필수
        // if (vstmtPrdDd.trim() == "") {
        //     await $c.win.alert("결제조건 선택 시 결제일자는 필수입력사항입니다.");
        //     tb_Grid1.setFocusedCell(rowIndex, "stmtPrdDd", true);
        //     ds_collMoneyCond.setCellData(rowIndex, "stmtPrdDd", vTmpData);
        //     return false;
        // }

        if (vstmtPrdDd < 1 || vstmtPrdDd > 60 && scwin.gJudgeYn == "0") {
            await $c.win.alert("결제기한을 정확하게 입력해주십시오(1일 초과 및 60일 이하만 가능) 재무팀에게 결재기한 요청하십시오.");
            ds_collMoneyCond.setCellData(rowIndex, "stmtPrdDd", vTmpData);
            ds_collMoneyCond.setCellData(rowIndex, "stmtPrdDd", vTmpData);
            tb_Grid1.setFocusedCell(rowIndex, "stmtPrdDd", true);
            return false;
        }

    } else if (colid == "adptDt") {
        for (var i = 0; i < ds_collMoneyCond.getTotalRow(); i++) {
            if ((rowIndex != i) && (ds_collMoneyCond.getCellData(rowIndex, "adptDt") == ds_collMoneyCond.getCellData(i, "adptDt"))) {
                await $c.win.alert("선택하신 적용일자가 이미 입력이 되어있습니다.")
                ds_collMoneyCond.setCellData(rowIndex, "adptDt", "");
                return false
            }
        }
    }

    // for=tb_Grid1 event=OnCloseUp(row,colid)
    if (document.activeElement.getAttribute('data-inputtype') == 'textImage') return;
    // let colid = tb_Grid1.getColumnID(columnIndex)
    var vCollMoneyCntShtCd = ds_collMoneyCond.getCellData(rowIndex, "collMoneyCntShtCd"); // 수금수단
    if (colid == "collMoneyCntShtCd") {
        if (vCollMoneyCntShtCd == "20") {
            // 수금수단이 어음인 경우
            ds_collMoneyCond.setCellData(rowIndex, "draftDdCnt", 0);
            tb_Grid1.setCellReadOnly(rowIndex, "draftDdCnt", false);
        } else {
            // 수금수단이 현금인 경우
            tb_Grid1.setCellReadOnly(rowIndex, "draftDdCnt", true);
            ds_collMoneyCond.setCellData(rowIndex, "draftDdCnt", 0);
        }
    } else if (colid == "stmtPrdClsCd") {
        vstmtPrdClsCd = ds_collMoneyCond.getCellData(rowIndex, "stmtPrdClsCd");
        // 수시인경우
        tb_Grid1.setCellReadOnly(rowIndex, "stmtPrdDd", false);
        ds_collMoneyCond.setCellData(rowIndex, "stmtPrdDd", "30");
    }
};


