// 지급일 Combo 선택
// for=tb_Grid2 event=OnCloseUp(row,colid)
scwin.tb_Grid2_onafteredit = function (rowIndex, columnIndex, value) {
    if (document.activeElement.getAttribute('data-inputtype') == 'textImage') return;
    var payCycCd = ds_payCond.getCellData(rowIndex, "payCycCd");
    var vPayCntShtCd = ds_payCond.getCellData(rowIndex, "payCntShtCd");
    let colid = tb_Grid2.getColumnID(columnIndex)
    // 지급주기, 주기일콤보를 여는 경우
    if (colid == "payCycCd") {
        if (payCycCd == 0) {
            // 수시인 경우
            ds_payCond.setCellData(rowIndex, "payDd", "");
            tb_Grid2.setCellReadOnly(rowIndex, "payDd", true);
        } else if (payCycCd != 0) {
            // 익월, 익익월인 경우
            tb_Grid2.setCellReadOnly(rowIndex, "payDd", false);
            ds_payCond.setCellData(rowIndex, "payDd", "10");
        }
    }

    if (colid == "payCntShtCd") {
        if (["25", "50"].includes(vPayCntShtCd)) {   // 전자결재(25)이나 실물어음(50)인 경우
            tb_Grid2.setCellReadOnly(rowIndex, "draftDdCntCd", false);
        } else {
            tb_Grid2.setCellReadOnly(rowIndex, "draftDdCntCd", true);
            ds_payCond.setCellData(rowIndex, "draftDdCntCd", "");
        }
    }
};


// 현금과 어음비율 값 입력
// for=ds_payCond  event=onColumnChanged(row,colid)
scwin.ds_payCond_oncelldatachange = function (info) {
    let row = info.rowIndex
    let colid = info.colID;
    let cashRt = ds_payCond.getCellData(row, "cashRt");
    let draftRt = ds_payCond.getCellData(row, "draftRt");
    // 현금과 어음 비율을 100으로
    if (colid == "cashRt") {
        if (cashRt >= 0 && cashRt <= 100) {
            draftVal = 100 - cashRt;
            ds_payCond.setCellData(row, "draftRt", draftVal);
        } else {
            $c.win.alert("현금비율은 입력값이 100보다 클 수 없습니다.");
            ds_payCond.setCellData(row, "cashRt", 100 - ds_payCond.getCellData(row, "draftRt"));
        }
    }

    if (colid == "draftRt") {
        if (draftRt >= 0 && draftRt <= 100) {
            cashVal = 100 - draftRt;
            ds_payCond.setCellData(row, "cashRt", cashVal);
        } else {
            $c.win.alert("어음비율은 입력값이 100보다 클 수 없습니다.");
            ds_payCond.setCellData(row, "draftRt", 100 - ds_payCond.getCellData(row, "cashRt"));
        }
    }
};

