scwin.sbm_saveAccountCustomer_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Code == -1) {
        scwin.txt_createYn = "0";
        scwin.txt_updateYn = "0";
        return;
    }

    ds_collMoneyCond.initRowStatus();
    ds_payCond.initRowStatus();
    ds_payAcnt.initRowStatus();

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    var vCreateYn = scwin.txt_createYn;
    scwin.f_ContentsDisable();
    $c.gus.cfEnableBtnOnly([b_Create, b_Update, b_Create2, b_Update2]);
    $c.gus.cfDisableBtn([b_Cancel, b_Cancel2, b_Save, b_Save2]);

    if (vCreateYn == "1") {
        scwin.f_Retrieve();
    }

    scwin.txt_createYn = "0";
    scwin.txt_updateYn = "0";
};


