    // AS-IS: for=ds_accountCustomer event=CanRowPosChange(row)
    if (["0"].includes(scwin.txt_saveType)) { // 신규 행 추가시
        // 신규추가후 셀 포커스 이동시 막는 로직
        let lastRow = gr_accountCustomer.getTotalRow() - 1;
        gr_accountCustomer.setFocusedCell(lastRow, "clntNm", false);
        if (lastRow == rowIndex) return;
        $c.win.alert("거래처 신규등록이나 변경사항을 저장하신 후에 다른 거래처정보로 이동하실수 있습니다.");
        return;
    } else if (["1"].includes(scwin.txt_saveType)) { //  수정
        gr_accountCustomer.setFocusedCell(scwin.updateRow, "clntNm", false);
        if (scwin.updateRow == rowIndex) return;
        $c.win.alert("거래처 신규등록이나 변경사항을 저장하신 후에 다른 거래처정보로 이동하실수 있습니다.");
        return;
    }

    // AS-IS: for=ds_accountCustomer event=OnRowPosChanged(row)
    let row = rowIndex;

    scwin.txt_clntNo = ds_accountCustomer.getCellData(rowIndex, "clntNo");
    var vClntKndCd = ds_accountCustomer.getCellData(rowIndex, "clntKndCd"); // 업무구분
    var vRowStatus = ds_accountCustomer.getRowStatusValue(rowIndex);	// 현재 row 상태 (입력,삭제 등)

    if (vRowStatus == 0 || vRowStatus == 1) {
        scwin.f_ContentsDisable();
    } else {
        scwin.f_ContentsEnable();
    }

    if (vClntKndCd == "AC") {
        gr_accountCustomer.setReadOnly("grid", false);
        tb_Grid1.setReadOnly("grid", false);
        tb_Grid2.setReadOnly("grid", false);
        tb_Grid3.setReadOnly("grid", false);
    } else {
        gr_accountCustomer.setReadOnly("grid", true);
        tb_Grid1.setReadOnly("grid", true);
        tb_Grid2.setReadOnly("grid", true);
        tb_Grid3.setReadOnly("grid", true);
    }

    if (ds_accountCustomer.getCellData(rowIndex, "clntNo") != "") {
        if (rowIndex >= 0) {
            scwin.f_RetrieveCollPayAcnt();
            // 아래 action이 뭔지 모름..
            // $c.sbm.execute(sbm_payAcnt);    // ds_payAcnt.Reset();
            // $c.sbm.execute(sbm_collMoneyCond);    // ds_collMoneyCond.Reset();
            // $c.sbm.execute(sbm_payCond);    // ds_payCond.Reset();
        }
        else {
            // asis에서는 조회 버튼을 클릭하면 아래 로직을 탄후에 위에 로직을탐.
            // to-do
            // 얘네는 asis에서도 안쓰는거같아서 일단 주석처리.
            // $c.sbm.execute(sbm_payAcnt);    // ds_payAcnt.Reset();
            // $c.sbm.execute(sbm_collMoneyCond);    // ds_collMoneyCond.Reset();
            // $c.sbm.execute(sbm_payCond);    // ds_payCond.Reset();
        }
    }
};


