// for="accountClntKndCd" event=onSelChange()
scwin.accountClntKndCd_onchange = function (info) {
    // 거래처 종류에 따라 Check할 부분 설정 
    var vAccountClntKndCode = accountClntKndCd.getValue();
    if (vAccountClntKndCode == "BK") {
        //금융기관인 경우
        $c.gus.cfEnableObj(bank_search, true);  // 은행팝업 이미지 활성화
        $c.gus.cfEnableObj(emp_search, false);  // 사원팝업 이미지 비활성화
        empNo.setValue("");
        empNm.setValue("");
        crnLabel.changeClass("", "req"); // crn.mandatory = "true";
        crn.setMandatory(true); // crn.validExp = "사업자번호:yes";
        comp_fncInstCd.mandatory = "true";
        comp_fncInstCd.validExp = "은행코드:yes";
        empNo.mandatory = "false";
        empNo.validExp = "";
        // $c.gus.cfRefreshMandSign();// to-do 공통
    } else if (vAccountClntKndCode == "EM") {
        //사원인 경우
        $c.gus.cfEnableObj(bank_search, false);  // 은행팝업 이미지 비활성화
        $c.gus.cfEnableObj(emp_search, true);  // 사원팝업 이미지 활성화
        comp_fncInstCd.setValue("");
        comp_fncInstNm.setValue("");
        crnLabel.changeClass("req", ""); // crn.mandatory = "false";
        crn.setMandatory(false); // crn.validExp = "사업자번호:no";
        comp_fncInstCd.mandatory = "false";
        comp_fncInstCd.validExp = "";
        empNo.mandatory = "true";
        empNo.validExp = "사원번호:yes";
        // $c.gus.cfRefreshMandSign();// to-do 공통
    } else if (vAccountClntKndCode == "GR") {
        $c.gus.cfEnableObj(bank_search, false);  // 은행팝업 이미지 비활성화
        $c.gus.cfEnableObj(emp_search, false);  // 사원팝업 이미지 비활성화
        comp_fncInstCd.setValue("");
        comp_fncInstNm.setValue("");
        empNo.setValue("");
        empNm.setValue("");
        crnLabel.changeClass("", "req"); // crn.mandatory = "true";
        crn.setMandatory(true); // crn.validExp = "사업자번호:yes";
        comp_fncInstCd.mandatory = "false";
        comp_fncInstCd.validExp = "";
        empNo.mandatory = "false";
        empNo.validExp = "";
        // $c.gus.cfRefreshMandSign();// to-do 공통
    }
};

// for=clntBusiClsCd event=OnSelChange()
scwin.clntBusiClsCd_onchange = function (info) {
    var vClntBusiClsCdIndex = clntBusiClsCd.getValue();
    if (vClntBusiClsCdIndex == 0) {
        //법인사업자
        crn.setMandatory(true);
        crn.validExp = "사업자번호:yes";
        // $c.gus.cfRefreshMandSign();// to-do 공통
    } else if (vClntBusiClsCdIndex == 1) {
        //개인사업자
        crn.setMandatory(true);
        crn.validExp = "사업자번호:yes";
        // $c.gus.cfRefreshMandSign();// to-do 공통
    } else if (vClntBusiClsCdIndex == 2 || vClntBusiClsCdIndex == 3) {
        crn.setMandatory(false);
        crn.validExp = "";
        // $c.gus.cfRefreshMandSign();// to-do 공통
    }
};

