scwin.ds_collMoneyCond_onrowpositionchange = function (info) {

    let row = info.newRowIndex;
    var vConfirmYn = ds_collMoneyCond.getCellData(row, "confirmYn");
    if (vConfirmYn == "1") {
        tb_Grid1.setCellReadOnly(row, 'adptDt', true);
        tb_Grid1.setCellReadOnly(row, 'collMoneyAcctDeptNm', true);
        tb_Grid1.setCellReadOnly(row, 'stmtPrdClsCd', true);
        tb_Grid1.setCellReadOnly(row, 'stmtPrdDd', true);
        tb_Grid1.setCellReadOnly(row, 'collMoneyCntShtCd', true);
        tb_Grid1.setCellReadOnly(row, 'draftDdCnt', true);
        tb_Grid1.setCellReadOnly(row, 'collMoneyCrcCd', true);
        tb_Grid1.setCellReadOnly(row, 'collMoneyBankbookNo', true);
    } else {
        if (ds_collMoneyCond.getRowStatusValue(row) != 0) {
            tb_Grid1.setCellReadOnly(row, 'adptDt', false);
        } else {
            tb_Grid1.setCellReadOnly(row, 'adptDt', true);
        }
        tb_Grid1.setCellReadOnly(row, 'collMoneyAcctDeptNm', false);
        tb_Grid1.setCellReadOnly(row, 'stmtPrdClsCd', false);
        tb_Grid1.setCellReadOnly(row, 'stmtPrdDd', false);
        tb_Grid1.setCellReadOnly(row, 'collMoneyCntShtCd', false);
        tb_Grid1.setCellReadOnly(row, 'draftDdCnt', false);
        tb_Grid1.setCellReadOnly(row, 'collMoneyCrcCd', false);
        tb_Grid1.setCellReadOnly(row, 'collMoneyBankbookNo', false);
    }
};

