// 이게 전환이 맞는지 확인필요.
// Gauce Tab선택시 행추가, 행수정, 행삭제 버튼 활성화 비활성화
// for=mxTab event=OnSelChanged(index)
scwin.mxTab_onchange = function (tabId, index, userTabId) {
    switch (index) {
        case 0:
            scwin.txt_payIdx = "1";
            if (["0", "1"].includes(scwin.txt_saveType)) {  // 0:신규, 1:수정, 2:조회, 3:저장
                $c.gus.cfEnableBtnOnly([bAddRow, bUndoRow, bDeleteRow]);
            }
            break;
        case 1:
            scwin.txt_payIdx = "2";
            if (["0", "1"].includes(scwin.txt_saveType)) {  // 0:신규, 1:수정, 2:조회, 3:저장
                $c.gus.cfEnableBtnOnly([bAddRow1, bUndoRow1, bDeleteRow1]);
            }
            break;
        case 2:
            scwin.txt_payIdx = "3";
            if (["0", "1"].includes(scwin.txt_saveType)) {
                $c.gus.cfEnableBtnOnly([bAddRow2, bUndoRow2, bDeleteRow2]);
            }
            break;
        case 3:
            scwin.txt_payIdx = "4";
            if (["0", "1"].includes(scwin.txt_saveType)) {
                $c.gus.cfEnableBtnOnly([bAddRow, bUndoRow, bDeleteRow]);
            }
            break;
        default:
            break;
    }
};


scwin.tb_Grid2_onbeforeedit = function (rowIndex, columnIndex, value) {

    let colid = tb_Grid2.getColumnID(columnIndex);

    if (colid == "payAcctDeptNm") {
        return false; // 편집모드 진입 차단
    }

    return true;
};
